import{_ as a,c as e,o as r,a1 as d}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Расширенные возможности Clawdbot: Конфигурация и инструменты","description":"Изучите расширенную конфигурацию Clawdbot, включая настройку AI моделей, многоагентное сотрудничество, автоматизацию браузера, инструменты выполнения команд, веб-поиск, визуальный интерфейс Canvas, голосовое управление, систему памяти, Cron-задачи, платформу навыков, безопасную песочницу и удаленный Gateway.","frontmatter":{"title":"Расширенные возможности Clawdbot: Конфигурация и инструменты","sidebarTitle":"Разблокируйте сверхспособности AI","subtitle":"Расширенные возможности","description":"Изучите расширенную конфигурацию Clawdbot, включая настройку AI моделей, многоагентное сотрудничество, автоматизацию браузера, инструменты выполнения команд, веб-поиск, визуальный интерфейс Canvas, голосовое управление, систему памяти, Cron-задачи, платформу навыков, безопасную песочницу и удаленный Gateway.","prerequisite":["start/getting-started","start/gateway-startup"],"order":185},"headers":[],"relativePath":"ru/moltbot/moltbot/advanced/index.md","filePath":"ru/moltbot/moltbot/advanced/index.md"}'),o={name:"ru/moltbot/moltbot/advanced/index.md"};function l(h,t,i,n,s,b){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="расширенные-возможности" tabindex="-1">Расширенные возможности <a class="header-anchor" href="#расширенные-возможности" aria-label="Permalink to &quot;Расширенные возможности&quot;">​</a></h1><h2 id="обзор-главы" tabindex="-1">Обзор главы <a class="header-anchor" href="#обзор-главы" aria-label="Permalink to &quot;Обзор главы&quot;">​</a></h2><p>Эта глава подробно описывает расширенные возможности Clawdbot, помогая вам в полной мере использовать мощь AI-ассистента. От настройки AI моделей и многоагентного сотрудничества до автоматизации браузера, системы памяти и голосовых функций — вы можете выбирать темы для изучения в соответствии с вашими потребностями.</p><div class="info custom-block"><p class="custom-block-title">Предварительные условия</p><p>Перед изучением этой главы выполните следующее:</p><ul><li><a href="./../../start/getting-started/">Быстрый старт</a></li><li><a href="./../../start/gateway-startup/">Запуск Gateway</a></li></ul></div><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>В соответствии с вашими потребностями вы можете выбрать разные пути обучения:</p><h3 id="🚀-путь-быстрого-старта-рекомендуется-новичкам" tabindex="-1">🚀 Путь быстрого старта (рекомендуется новичкам) <a class="header-anchor" href="#🚀-путь-быстрого-старта-рекомендуется-новичкам" aria-label="Permalink to &quot;🚀 Путь быстрого старта (рекомендуется новичкам)&quot;">​</a></h3><ol><li><a href="./models-auth/">AI модели и настройка аутентификации</a> - Настройте предпочитаемые AI модели</li><li><a href="./tools-exec/">Инструменты выполнения команд и утверждения</a> - Позвольте AI безопасно выполнять команды</li><li><a href="./tools-web/">Инструменты веб-поиска и парсинга</a> - Расширьте возможности получения знаний AI</li></ol><h3 id="🤖-путь-расширения-возможностеи-ai" tabindex="-1">🤖 Путь расширения возможностей AI <a class="header-anchor" href="#🤖-путь-расширения-возможностеи-ai" aria-label="Permalink to &quot;🤖 Путь расширения возможностей AI&quot;">​</a></h3><ol><li><a href="./session-management/">Управление сеансами и многоагентная система</a> - Понимание механизма сотрудничества AI</li><li><a href="./memory-system/">Система памяти и векторный поиск</a> - Позвольте AI запоминать важную информацию</li><li><a href="./skills-platform/">Платформа навыков и ClawdHub</a> - Используйте и делитесь наборами навыков</li></ol><h3 id="🔧-путь-инструментов-автоматизации" tabindex="-1">🔧 Путь инструментов автоматизации <a class="header-anchor" href="#🔧-путь-инструментов-автоматизации" aria-label="Permalink to &quot;🔧 Путь инструментов автоматизации&quot;">​</a></h3><ol><li><a href="./tools-browser/">Инструменты автоматизации браузера</a> - Автоматизация веб-операций</li><li><a href="./cron-automation/">Cron-задачи и Webhook</a> - Запланированные задачи и события</li><li><a href="./remote-gateway/">Удаленный Gateway и Tailscale</a> - Удаленный доступ к вашему AI-ассистенту</li></ol><h3 id="🎨-путь-интерактивного-опыта" tabindex="-1">🎨 Путь интерактивного опыта <a class="header-anchor" href="#🎨-путь-интерактивного-опыта" aria-label="Permalink to &quot;🎨 Путь интерактивного опыта&quot;">​</a></h3><ol><li><a href="./canvas/">Визуальный интерфейс Canvas и A2UI</a> - Интерфейс визуального взаимодействия</li><li><a href="./voice-tts/">Голосовое управление и текст в речь</a> - Функции голосового взаимодействия</li></ol><h3 id="🔒-путь-безопасности-и-развертывания" tabindex="-1">🔒 Путь безопасности и развертывания <a class="header-anchor" href="#🔒-путь-безопасности-и-развертывания" aria-label="Permalink to &quot;🔒 Путь безопасности и развертывания&quot;">​</a></h3><ol><li><a href="./security-sandbox/">Безопасность и изоляция песочницы</a> - Глубокое понимание механизмов безопасности</li><li><a href="./remote-gateway/">Удаленный Gateway и Tailscale</a> - Безопасный удаленный доступ</li></ol><h2 id="навигация-по-подстраницам" tabindex="-1">Навигация по подстраницам <a class="header-anchor" href="#навигация-по-подстраницам" aria-label="Permalink to &quot;Навигация по подстраницам&quot;">​</a></h2><h3 id="основная-конфигурация" tabindex="-1">Основная конфигурация <a class="header-anchor" href="#основная-конфигурация" aria-label="Permalink to &quot;Основная конфигурация&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Тема</th><th>Описание</th><th>Предполагаемое время</th></tr></thead><tbody><tr><td><a href="./models-auth/">AI модели и настройка аутентификации</a></td><td>Настройка различных провайдеров AI моделей и способов аутентификации, включая Anthropic, OpenAI, OpenRouter, Ollama и другие</td><td>15 минут</td></tr><tr><td><a href="./session-management/">Управление сеансами и многоагентная система</a></td><td>Изучение моделей сеансов, изоляции сеансов, сотрудничества подагентов, сжатия контекста и других основных концепций</td><td>20 минут</td></tr></tbody></table><h3 id="система-инструментов" tabindex="-1">Система инструментов <a class="header-anchor" href="#система-инструментов" aria-label="Permalink to &quot;Система инструментов&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Тема</th><th>Описание</th><th>Предполагаемое время</th></tr></thead><tbody><tr><td><a href="./tools-browser/">Инструменты автоматизации браузера</a></td><td>Использование инструментов браузера для автоматизации веб-страниц, создания снимков экрана, управления формами и других операций</td><td>25 минут</td></tr><tr><td><a href="./tools-exec/">Инструменты выполнения команд и утверждения</a></td><td>Настройка и использование инструмента exec, понимание механизма безопасного утверждения и контроля разрешений</td><td>15 минут</td></tr><tr><td><a href="./tools-web/">Инструменты веб-поиска и парсинга</a></td><td>Использование инструментов web_search и web_fetch для веб-поиска и парсинга содержимого</td><td>20 минут</td></tr></tbody></table><h3 id="интерактивныи-опыт" tabindex="-1">Интерактивный опыт <a class="header-anchor" href="#интерактивныи-опыт" aria-label="Permalink to &quot;Интерактивный опыт&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Тема</th><th>Описание</th><th>Предполагаемое время</th></tr></thead><tbody><tr><td><a href="./canvas/">Визуальный интерфейс Canvas и A2UI</a></td><td>Понимание механизма推送 Canvas A2UI, операций визуального интерфейса и настройки пользовательского интерфейса</td><td>20 минут</td></tr><tr><td><a href="./voice-tts/">Голосовое управление и текст в речь</a></td><td>Настройка Voice Wake, Talk Mode и провайдеров TTS для реализации голосового взаимодействия</td><td>15 минут</td></tr></tbody></table><h3 id="умное-расширение" tabindex="-1">Умное расширение <a class="header-anchor" href="#умное-расширение" aria-label="Permalink to &quot;Умное расширение&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Тема</th><th>Описание</th><th>Предполагаемое время</th></tr></thead><tbody><tr><td><a href="./memory-system/">Система памяти и векторный поиск</a></td><td>Настройка и использование системы памяти (SQLite-vec, FTS5, гибридный поиск)</td><td>25 минут</td></tr><tr><td><a href="./skills-platform/">Платформа навыков и ClawdHub</a></td><td>Понимание системы навыков, Bundled/Managed/Workspace навыков, интеграции ClawdHub</td><td>20 минут</td></tr></tbody></table><h3 id="автоматизация-и-развертывание" tabindex="-1">Автоматизация и развертывание <a class="header-anchor" href="#автоматизация-и-развертывание" aria-label="Permalink to &quot;Автоматизация и развертывание&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Тема</th><th>Описание</th><th>Предполагаемое время</th></tr></thead><tbody><tr><td><a href="./cron-automation/">Cron-задачи и Webhook</a></td><td>Настройка запланированных задач, триггеров Webhook, Gmail Pub/Sub и других функций автоматизации</td><td>20 минут</td></tr><tr><td><a href="./remote-gateway/">Удаленный Gateway и Tailscale</a></td><td>Удаленный доступ к Gateway через Tailscale Serve/Funnel или SSH-туннель</td><td>15 минут</td></tr></tbody></table><h3 id="механизмы-безопасности" tabindex="-1">Механизмы безопасности <a class="header-anchor" href="#механизмы-безопасности" aria-label="Permalink to &quot;Механизмы безопасности&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Тема</th><th>Описание</th><th>Предполагаемое время</th></tr></thead><tbody><tr><td><a href="./security-sandbox/">Безопасность и изоляция песочницы</a></td><td>Понимание модели безопасности, контроля разрешений инструментов, изоляции Sandbox, развертывания в Docker</td><td>20 минут</td></tr></tbody></table><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения изучения этой главы вы можете:</p><ol><li><strong>Глубокое изучение</strong> - Просмотрите <a href="./../../faq/troubleshooting/">Устранение неполадок</a> для решения возникающих проблем</li><li><strong>Понимание развертывания</strong> - Просмотрите <a href="./../../appendix/deployment/">Варианты развертывания</a> для развертывания Clawdbot в производственной среде</li><li><strong>Разработка расширений</strong> - Просмотрите <a href="./../../appendix/development/">Руководство по разработке</a> для изучения разработки плагинов и вклада в код</li><li><strong>Просмотр конфигурации</strong> - Справочник <a href="./../../appendix/config-reference/">Полная ссылка на конфигурацию</a> для ознакомления со всеми параметрами конфигурации</li></ol><div class="tip custom-block"><p class="custom-block-title">Рекомендации по обучению</p><p>Рекомендуется выбирать путь обучения в соответствии с вашими реальными потребностями. Если вы не уверены, с чего начать, вы можете постепенно изучать по «пути быстрого старта», а другие темы можно изучить глубже по мере необходимости.</p></div>',33)])])}const f=a(o,[["render",l]]);export{u as __pageData,f as default};
